   177	/* An independent time proc for defrag.  While defrag is running, this is called much more often
   178	 *  than the server cron.  Frequent short calls provides low latency impact. */
   179	static long long activeDefragTimeProc(struct aeEventLoop *eventLoop, long long id, void *clientData) {
   180	    UNUSED(eventLoop);
   181	    UNUSED(id);
   182	    UNUSED(clientData);
   183	
   184	    // This timer shouldn't be registered unless there's work to do.
   185	    serverAssert(defrag.current_stage || listLength(defrag.remaining_stages) > 0);
   186	
   187	    if (!server.active_defrag_enabled) {
   188	        // Defrag has been disabled while running
   189	        endDefragCycle(false);
   190	        return AE_NOMORE;
   191	    }
   192	
   193	    if (hasActiveChildProcess()) {
   194	        // If there's a child process, pause the defrag, polling until the child completes.
   195	        defrag.timeproc_end_time = 0; // prevent starvation recovery
   196	        return 100;
   197	    }
   198	
   199	    monotime starttime = getMonotonicUs();
   200	    int dutyCycleUs = computeDefragCycleUs();
   201	    monotime endtime = starttime + dutyCycleUs;
   202	    bool haveMoreWork = true;
   203	
   204	    mstime_t latency;
   205	    latencyStartMonitor(latency);
   206	
   207	    do {
   208	        if (!defrag.current_stage) {
   209	            defrag.current_stage = listNodeValue(listFirst(defrag.remaining_stages));
   210	            listDelNode(defrag.remaining_stages, listFirst(defrag.remaining_stages));
   211	            // Initialize the stage with endtime==0
   212	            doneStatus status = defrag.current_stage->stage_fn(0, defrag.current_stage->target, defrag.current_stage->privdata);
   213	            serverAssert(status == DEFRAG_NOT_DONE); // Initialization should always return DEFRAG_NOT_DONE
   214	        }
   215	
   216	        doneStatus status = defrag.current_stage->stage_fn(endtime, defrag.current_stage->target, defrag.current_stage->privdata);
   217	        if (status == DEFRAG_DONE) {
   218	            zfree(defrag.current_stage);
   219	            defrag.current_stage = NULL;
   220	        }
   221	
   222	        haveMoreWork = (defrag.current_stage || listLength(defrag.remaining_stages) > 0);
   223	        /* If we've completed a stage early, and still have a standard time allotment remaining,
   224	         * we'll start another stage.  This can happen when defrag is running infrequently, and
   225	         * starvation protection has increased the duty-cycle. */
   226	    } while (haveMoreWork && getMonotonicUs() <= endtime - server.active_defrag_cycle_us);
   227	
   228	    latencyEndMonitor(latency);
   229	    latencyAddSampleIfNeeded("active-defrag-cycle", latency);
   230	    latencyTraceIfNeeded(db, active_defrag_cycle, latency);
   231	    if (haveMoreWork) {
   232	        return computeDelayMs(endtime);
   233	    } else {
   234	        endDefragCycle(true);
   235	        return AE_NOMORE; // Ends the timer proc
   236	    }
   237	}
