   240	/* During long running scripts, or while loading, there is a periodic function for handling other
   241	 * actions.  This interface allows defrag to continue running, avoiding a single long defrag step
   242	 * after the long operation completes. */
   243	void defragWhileBlocked(void) {
   244	    // This is called infrequently, while timers are not active.  We might need to start defrag.
   245	    if (!defragIsRunning()) monitorActiveDefrag();
   246	
   247	    if (!defragIsRunning()) return;
   248	
   249	    // Save off the timeproc_id.  If we have a normal termination, it will be cleared.
   250	    long long timeproc_id = defrag.timeproc_id;
   251	
   252	    // Simulate a single call of the timer proc
   253	    long long reschedule_delay = activeDefragTimeProc(NULL, 0, NULL);
   254	    if (reschedule_delay == AE_NOMORE) {
   255	        // If it's done, deregister the timer
   256	        aeDeleteTimeEvent(server.el, timeproc_id);
   257	    }
   258	    /* Otherwise, just ignore the reschedule_delay, the timer will pop the next time that the
   259	     * event loop can process timers again. */
