   302	/* decide if defrag is needed, and at what CPU effort to invest in it */
   303	static void updateDefragCpuPercent(void) {
   304	    size_t frag_bytes;
   305	    float frag_pct = getAllocatorFragmentation(&frag_bytes);
   306	    if (server.active_defrag_cpu_percent == 0) {
   307	        if (frag_pct < server.active_defrag_threshold_lower ||
   308	            frag_bytes < server.active_defrag_ignore_bytes) return;
   309	    }
   310	
   311	    /* Calculate the adaptive aggressiveness of the defrag based on the current
   312	     * fragmentation and configurations. */
   313	    int cpu_pct = INTERPOLATE(frag_pct, server.active_defrag_threshold_lower, server.active_defrag_threshold_upper,
   314	                              server.active_defrag_cpu_min, server.active_defrag_cpu_max);
   315	    cpu_pct = LIMIT(cpu_pct, server.active_defrag_cpu_min, server.active_defrag_cpu_max);
   316	
   317	    /* Normally we allow increasing the aggressiveness during a scan, but don't
   318	     * reduce it, since we should not lower the aggressiveness when fragmentation
   319	     * drops. But when a configuration is made, we should reconsider it. */
   320	    if (cpu_pct > server.active_defrag_cpu_percent || server.active_defrag_configuration_changed) {
   321	        server.active_defrag_configuration_changed = 0;
   322	        if (defragIsRunning()) {
   323	            serverLog(LL_VERBOSE, "Changing active defrag CPU, frag=%.0f%%, frag_bytes=%zu, cpu=%d%%",
   324	                      frag_pct, frag_bytes, cpu_pct);
   325	        } else {
   326	            serverLog(LL_VERBOSE, "Starting active defrag, frag=%.0f%%, frag_bytes=%zu, cpu=%d%%",
   327	                      frag_pct, frag_bytes, cpu_pct);
   328	        }
   329	        server.active_defrag_cpu_percent = cpu_pct;
   330	    }
   331	}
